CREATE OR REPLACE VIEW view_tel_det_coll_collateral (membership_no, mem_name, member_group_no, member_group_name, loan_contract_no, contract_memno, contract_mem_name, contract_group_no, contract_group_name, principal_balance) AS SELECT sc_mem_m_membership_registered.membership_no
    , pka_com_function.fp_get_member_name( sc_mem_m_membership_registered.membership_no ) as mem_name
    , sc_mem_m_membership_registered.member_group_no
    , sc_mem_m_ucf_member_group.member_group_name
    , sc_lon_m_loan_card.loan_contract_no   
    , sc_lon_m_loan_card.membership_no as contract_memno  
    , pka_com_function.fp_get_member_name( sc_lon_m_loan_card.membership_no ) as contract_mem_name
    , ( select member_group_no 
        FROM sc_mem_m_membership_registered 
        where membership_no = sc_lon_m_loan_card.membership_no )as contract_group_no
    , pka_com_function.fp_get_group_name_mem( sc_lon_m_loan_card.membership_no ) as contract_group_name    
    , sc_lon_m_loan_card.principal_balance   
                      
    FROM sc_lon_m_loan_card,   
         sc_lon_m_contract_coll,   
         sc_mem_m_membership_registered ,
         sc_mem_m_ucf_member_group
         ,sc_lon_m_rule
   WHERE 1=1
   and sc_lon_m_rule.loan_type = sc_lon_m_loan_card.loan_type
   and ( sc_lon_m_loan_card.loan_contract_no = sc_lon_m_contract_coll.loan_contract_no )   
   and ( sc_lon_m_contract_coll.ref_own_no = sc_mem_m_membership_registered.membership_no )   
   and ( sc_mem_m_ucf_member_group.member_group_no = sc_mem_m_membership_registered.member_group_no )  
   and (  sc_lon_m_loan_card.principal_balance > 0 or (  sc_lon_m_rule.atm_status = '1' and  sc_lon_m_loan_card.close_status = '0' ) )  
   and ( sc_lon_m_contract_coll.status = '0' )   
   and ( sc_lon_m_contract_coll.collateral_type_code = '01' )    
   /* and      sc_mem_m_membership_registered.membership_no = '011239'  */

 
   order by sc_lon_m_loan_card.loan_contract_no
  , sc_lon_m_loan_card.membership_no;

